/* NN_02_Message_Parser v2.0.0
 * Parses Telegram messages and extracts chat_id, text, username
 * Handles multiple input paths: Execute Workflow, direct webhook, raw fields
 * 
 * IMPROVEMENTS v2.0.0:
 * - Added regex whitelist validation (§4.3 GEMINI.md)
 * - Enhanced input validation with explicit type checking
 * - Better error messages for debugging
 */

const input = $input.first()?.json;

// Handle multiple input paths
const bodyLayer = input?.body || input || {};
const message = bodyLayer.message || bodyLayer.channel_post || bodyLayer;

// === EXTRACT VALUES ===
const chat_id = message.chat?.id || bodyLayer.chat_id || input?.chat_id;
const text = message.text || bodyLayer.text || input?.text;
const username = message.from?.first_name || message.chat?.first_name || bodyLayer.username || 'Unknown';

// === VALIDATION FUNCTIONS (§4.3 GEMINI.md) ===

// Chat ID validation: must be positive integer (Telegram chat IDs are 64-bit integers)
const CHAT_ID_RE = /^\d+$/;
function validateChatId(id) {
  if (id === undefined || id === null) {
    return { valid: false, error: 'chat_id is required' };
  }

  const idStr = String(id).trim();
  if (!CHAT_ID_RE.test(idStr)) {
    return { valid: false, error: 'chat_id must be a positive integer' };
  }

  const idNum = Number(idStr);
  if (idNum < 0 || idNum > 9007199254740991) { // Max safe integer
    return { valid: false, error: 'chat_id out of valid range' };
  }

  return { valid: true, value: idNum };
}

// Text validation: 1-500 chars, printable characters only
const TEXT_RE = /^[\x20-\x7E\u00C0-\u017F\u0400-\u04FF\u0600-\u06FF\u4E00-\u9FFF\u3040-\u309F\u30A0-\u30FF\n\r\t]{1,500}$/;
function validateText(txt) {
  if (txt === undefined || txt === null) {
    return { valid: false, error: 'text is required' };
  }

  const txtStr = String(txt).trim();
  if (txtStr.length === 0) {
    return { valid: false, error: 'text cannot be empty' };
  }

  if (!TEXT_RE.test(txtStr)) {
    return { valid: false, error: 'text contains invalid characters' };
  }

  return { valid: true, value: txtStr };
}

// Username validation: alphanumeric + underscore, 1-100 chars
const USERNAME_RE = /^[\w\s]{1,100}$/;
function validateUsername(name) {
  const nameStr = String(name || '').trim();
  if (nameStr.length === 0) {
    return { valid: true, value: 'Unknown' }; // Default is OK
  }

  if (!USERNAME_RE.test(nameStr)) {
    return { valid: true, value: 'User' }; // Fallback to safe default
  }

  return { valid: true, value: nameStr.substring(0, 100) };
}

// === PERFORM VALIDATION ===
const chatIdResult = validateChatId(chat_id);
const textResult = validateText(text);
const usernameResult = validateUsername(username);

// Return validation errors
if (!chatIdResult.valid || !textResult.valid) {
  const errors = [];
  if (!chatIdResult.valid) errors.push(chatIdResult.error);
  if (!textResult.valid) errors.push(textResult.error);

  return [{
    json: {
      success: false,
      error_code: 'VALIDATION_ERROR',
      error_message: errors.join('; '),
      data: null,
      _meta: { 
        source: 'NN_02_Message_Parser', 
        timestamp: new Date().toISOString(), 
        workflow_id: $workflow.id 
      }
    }
  }];
}

// === SANITIZE FOR SQL (§4.4 GEMINI.md) ===
const safeText = textResult.value
  .replace(/\\/g, '\\\\')
  .replace(/'/g, "''")
  .substring(0, 500);

const safeUsername = usernameResult.value
  .replace(/\\/g, '\\\\')
  .replace(/'/g, "''")
  .substring(0, 100);

// === RETURN SUCCESS ===
return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      chat_id: chatIdResult.value,
      text: safeText,
      username: safeUsername,
      type: 'text'
    },
    _meta: { 
      source: 'NN_02_Message_Parser', 
      timestamp: new Date().toISOString(), 
      workflow_id: $workflow.id,
      version: '2.0.0'
    }
  }
}];
